import { Element, Component, h, Prop, State, Listen, Event, EventEmitter, Host, Watch } from '@stencil/core';
import { ChipMenuAligment, ChipMenuValueItem } from './wdpr-chip-menu.model';
import { KEYBOARD_KEYS } from '../../models/keycodes.model';
import { getInitialFocusIndex, findNextEnabledIndex } from './wdpr-chip-menu.utils';
import { generateRandId } from '../../utils/utils';
import { InlineMessageSize } from '../wdpr-inline-message/wdpr-inline-message.model';
import { RadialLoaderSize, RadialLabelPlacement } from '../wdpr-radial-loader/wdpr-radial-loader.model';

@Component({
  tag: 'wdpr-chip-menu',
  styleUrl: 'wdpr-chip-menu.css',
  scoped: true,
})
export class WdprChipMenu {
  private _listId: string;
  private _dropdownId: string;
  private _slotObserver: MutationObserver;
  private _resizeObserver: ResizeObserver;
  private _listEl: HTMLDivElement | null = null;
  private _cachedItems: HTMLWdprChipMenuItemElement[] | null = null;

  @Element() el!: HTMLElement;

  @State() _leadingSlot: HTMLElement | null = null;
  @State() _trailingSlot: HTMLElement | null = null;

  @State() _expanded: boolean = false;
  @State() _selectedValue: ChipMenuValueItem | null = null;
  @State() _readyToShow: boolean = false;
  @State() _focusedIndex: number = -1;
  @State() _measuredMaxHeight: string | null = null;
  @State() _activeDescendantId?: string = undefined;

  @Prop({ reflect: true }) value: string = '';
  @Prop({ reflect: true }) alignment: ChipMenuAligment = 'left';
  @Prop() maxViewableItems: number | null = null;
  @Prop() disabled: boolean = false;
  @Prop() noDivider: boolean = true;
  @Prop({ attribute: 'a11y-chip-label' }) a11yChipLabel!: string;
  @Prop({ attribute: 'a11y-list-label' }) a11yListLabel!: string;

  @Prop() isLoading: boolean = false;
  @Prop() loadingText: string = 'Loading...';
  @Prop() loaderSize: RadialLoaderSize = 'medium';
  @Prop() loaderLabelPlacement: RadialLabelPlacement = 'inline';
  @Prop() showLoaderLabel: boolean = true;
  @Prop() emptyText: string = 'No results.';
  @Prop() emptyTextSize: InlineMessageSize = 'default';
  @Prop() isErrorLoading: boolean = false;
  @Prop() errorText: string = 'Failed to load items. Please try again.';
  @Prop() errorTextSize: InlineMessageSize = 'default';

  @Event() wdprSelectionChange!: EventEmitter<{ selectedValue: { id: string; value: string; label: string } | null }>;

  @Watch('value')
  handleValueChanged() {
    this._syncSelectionFromValue();
  }

  @Watch('_selectedValue')
  updateSelectedValue() {
    this._syncSelectionItemsState();
  }

  @Watch('_expanded')
  handleExpandedChange(newValue: boolean) {
    if (!newValue) {
      this._removeAriaActivedescendant();
      this._setFocusIndex(null);
    }
  }

  @Watch('maxViewableItems')
  handleMaxViewableItemsChange() {
    requestAnimationFrame(() => {
      this._measureItemHeights();
    });
  }

  @Listen('wdprSelect')
  handleItemSelect(event: CustomEvent<{ value: string; label: string; id: string }>) {
    event.stopPropagation();
    const {
      detail: { value, label, id },
    } = event;

    this._updateSelectedValue(value, label, id);
    this._closeDropdown();
  }

  @Listen('click', { target: 'document' })
  handleDocumentClick(event: MouseEvent) {
    const path = (event.composedPath && event.composedPath()) || [];
    const clickInsideChipMenu = path.some(node => node === this.el);

    if (!clickInsideChipMenu && this._expanded) this._expanded = false;
  }

  componentWillLoad() {
    this._listId = `wdpr-chip-menu-list-${generateRandId()}`;
    this._dropdownId = `wdpr-chip-menu-${generateRandId()}`;
    this._resizeObserver = new ResizeObserver(() => this._measureItemHeights());
    this._updateSlots();
  }

  componentDidLoad() {
    requestAnimationFrame(() => {
      this._initAllItems();
      this._measureItemHeights();
      this._syncSelectionFromValue();
      if (this._listEl) {
        this._slotObserver.observe(this._listEl, { childList: true, subtree: true });
      }
    });

    this._slotObserver = new MutationObserver(mutations => {
      const items = mutations.flatMap(m => Array.from(m.addedNodes)).filter((n): n is HTMLElement => n.nodeType === Node.ELEMENT_NODE);

      if (items.length === 0) return;

      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      Promise.all(items.map(el => ('componentOnReady' in el ? (el as any).componentOnReady() : Promise.resolve()))).then(() => {
        this._invalidateItemsCache();
        this._initAllItems();
        this._measureItemHeights();
        this._syncSelectionFromValue();
      });
    });
  }

  disconnectedCallback() {
    this._slotObserver?.disconnect();
    this._resizeObserver?.disconnect();
  }

  private _getAllListItems(): HTMLWdprChipMenuItemElement[] {
    if (!this._cachedItems?.length) {
      this._cachedItems = Array.from(this.el?.querySelectorAll('wdpr-chip-menu-item'));
    }

    return this._cachedItems;
  }

  private _groupLastItems(): Set<HTMLWdprChipMenuItemElement> {
    const groupElements = Array.from(this.el.querySelectorAll('wdpr-chip-menu-group'));

    const lastItems: HTMLWdprChipMenuItemElement[] = [];

    for (const group of groupElements) {
      const items = Array.from(group.querySelectorAll('wdpr-chip-menu-item'));

      const lastItem = items[items.length - 1];

      if (lastItem) {
        lastItems.push(lastItem);
      }
    }

    return new Set<HTMLWdprChipMenuItemElement>(lastItems);
  }

  private async _initAllItems(): Promise<void> {
    this._invalidateItemsCache();
    const allItems = this._getAllListItems();

    if (allItems.length === 0) return;

    this._resizeObserver.disconnect();
    this._resizeObserver.observe(allItems[0]);

    const lastItem = allItems[allItems.length - 1];

    const groupLastItems = this._groupLastItems();

    for (const item of allItems) {
      if (this.noDivider || item === lastItem || groupLastItems.has(item)) {
        if (typeof item.hideDivider === 'function') {
          await item.hideDivider();
        }
      }
    }
  }

  private _closeDropdown() {
    this._expanded = false;
  }

  /**
   * Measures the height of the dropdown list and sets the max height for scrollable lists.
   * Calculates based on the number of visible items and their bounding rectangles.
   */
  private _measureItemHeights(): void {
    if (this.maxViewableItems == null || this.maxViewableItems <= 0) {
      this._measuredMaxHeight = null;
      this._readyToShow = true;

      return;
    }

    const allListItems: HTMLWdprChipMenuItemElement[] = this._getAllListItems();
    const listbox = this.el?.querySelector('.listbox');

    if (!listbox || allListItems.length === 0) {
      this._readyToShow = true;

      return;
    }

    if (allListItems.length <= this.maxViewableItems) {
      this._measuredMaxHeight = null;
      this._readyToShow = true;

      return;
    }

    const targetItem = allListItems[this.maxViewableItems - 1];
    const wrapperRect = listbox.getBoundingClientRect();
    const itemRect = targetItem.getBoundingClientRect();
    const itemHeight = targetItem.offsetHeight;

    if (itemHeight === 0) return;

    let calculatedHeight = Math.ceil(itemRect.bottom - wrapperRect.top);

    // Add Wrapper Padding (if available)
    const style = window.getComputedStyle(listbox);
    const paddingBottom = parseFloat(style.paddingBottom) || 0;
    calculatedHeight += paddingBottom;
    const newHeight = `${calculatedHeight}px`;

    if (this._measuredMaxHeight !== newHeight) {
      this._measuredMaxHeight = newHeight;
    }

    this._readyToShow = true;
  }

  private _renderList(): JSX.Element {
    const isScrollable = this.maxViewableItems != null && this.maxViewableItems > 0;

    return (
      <div ref={el => (this._listEl = el)} class="listbox" role="listbox" id={this._listId} tabindex={isScrollable ? 0 : undefined} aria-label={this.a11yListLabel || undefined}>
        <slot />
      </div>
    );
  }

  private _renderChipDropdown(): JSX.Element {
    return (
      <div
        class="chip-menu"
        tabindex={this.disabled ? -1 : 0}
        id={this._dropdownId}
        role="combobox"
        aria-haspopup="listbox"
        aria-disabled={this.disabled.toString()}
        aria-expanded={this._expanded.toString()}
        aria-controls={this._listId}
        aria-label={this.a11yChipLabel || undefined}
        aria-activedescendant={this._activeDescendantId}
        onClick={this._handleComboboxClick}
      >
        {this._leadingSlot && (
          <span class="chip-menu__icon">
            <slot name="leading-icon" onSlotchange={this._updateSlots} />
          </span>
        )}

        <span class="chip-menu__display-value">{this._displayValue}</span>

        {this._trailingSlot && (
          <span class="chip-menu__icon">
            <slot name="trailing-icon" onSlotchange={this._updateSlots} />
          </span>
        )}
      </div>
    );
  }

  private _renderListWrapper(): JSX.Element {
    const listContainerClasses = this._isListVisible ? 'chip-menu-list-container-visible' : 'chip-menu-list-container-invisible';

    return (
      <div class={`chip-menu-list-container ${listContainerClasses}`} style={{ height: this._measuredMaxHeight }}>
        {this._renderList()}
      </div>
    );
  }

  private _renderStatusMessage(): JSX.Element | null {
    const isEmpty = this._getAllListItems().length === 0;

    if (!this._expanded) return null;
    if (this.isLoading)
      return (
        <div class="loading-container" role="status" aria-live="polite" aria-atomic="true">
          <wdpr-radial-loader size={this.loaderSize} label={this.loadingText} labelPlacement={this.loaderLabelPlacement} showLabel={this.showLoaderLabel} />
        </div>
      );
    if (isEmpty && !this.isErrorLoading && !this.isLoading)
      return (
        <div class="empty-container">
          <wdpr-inline-message variant="informational" size={this.emptyTextSize} role="status" a11yLive="polite">{this.emptyText}</wdpr-inline-message>
        </div>
      );
    if (this.isErrorLoading && !this.isLoading)
      return (
        <div class="error-container">
          <wdpr-inline-message variant="error" size={this.errorTextSize} role="status" a11yLive="polite">{this.errorText}</wdpr-inline-message>
        </div>
      );

    return null;
  }

  /**
   * Handles keyboard navigation and accessibility for the dropdown.
   * Supports arrow keys, Enter, Space, Escape, and Tab for navigation and selection.
   * @param ev The keyboard event
   */
  private _handleKeydown = (ev: KeyboardEvent): void => {
    const items = this._getAllListItems();

    // Handle Enter and Space for toggle/selection
    if (ev.key === KEYBOARD_KEYS.ENTER || ev.key === KEYBOARD_KEYS.SPACE) {
      ev.preventDefault();
      if (!this._expanded) {
        this._expanded = true;
        const startIndex = getInitialFocusIndex(items, 'down');
        this._focusItemAtIndex(startIndex, items);
      } else {
        const focusedItem = items[this._focusedIndex];
        if (focusedItem && !focusedItem.disabled) {
          focusedItem.click();
        }
      }

      return;
    }

    if (ev.key === KEYBOARD_KEYS.ARROW_DOWN) {
      ev.preventDefault();
      if (!this._expanded) {
        this._expanded = true;
        const startIndex = getInitialFocusIndex(items, 'down');
        this._focusItemAtIndex(startIndex, items);

        return;
      }
      // Move focus to next enabled item
      const nextIndex = findNextEnabledIndex(items, this._focusedIndex, 'down');
      this._focusItemAtIndex(nextIndex, items);
    }

    if (ev.key === KEYBOARD_KEYS.ARROW_UP) {
      ev.preventDefault();
      if (!this._expanded) {
        this._expanded = true;
        const startIndex = getInitialFocusIndex(items, 'up');
        this._focusItemAtIndex(startIndex, items);

        return;
      }
      // Move focus to previous enabled item
      const prevIndex = findNextEnabledIndex(items, this._focusedIndex, 'up');
      this._focusItemAtIndex(prevIndex, items);
    }

    if (ev.key === KEYBOARD_KEYS.ESCAPE && this._expanded) {
      ev.preventDefault();
      ev.stopPropagation();
      this._closeDropdown();
    }

    if (ev.key === KEYBOARD_KEYS.TAB) {
      this._closeDropdown();
    }
  };

  /**
   * Sets focus to the item at the given index, updates ARIA attributes, and scrolls it into view.
   * @param index The index of the item to focus
   * @param items The array of dropdown items
   */
  private _focusItemAtIndex(index: number, items: HTMLWdprChipMenuItemElement[]): void {
    this._setFocusIndex(index);
    this._updateAriaActivedescendant(items[index]);

    // Scroll the focused item into view
    const focusedItem = items[index];
    if (focusedItem) {
      this._scrollIntoItem(focusedItem);
    }
  }

  private _scrollIntoItem(item: HTMLWdprChipMenuItemElement): void {
    const listbox = this.el?.querySelector('.listbox');
    if (listbox) {
      item.scrollIntoView({ block: 'nearest', inline: 'nearest' });
    }
  }

  private _setFocusIndex(index: number | null): void {
    const items = this._getAllListItems();
    items.forEach((item, i) => {
      item.isFocused = i === index;
    });

    this._focusedIndex = index == null ? -1 : index;
  }

  private _updateAriaActivedescendant(item: HTMLWdprChipMenuItemElement): void {
    this._activeDescendantId = item?.id;
  }

  private _removeAriaActivedescendant(): void {
    this._activeDescendantId = undefined;
  }

  private _invalidateItemsCache(): void {
    this._cachedItems = null;
  }

  private _syncSelectionFromValue(): void {
    const allItems = this._getAllListItems();

    for (const item of allItems) {
      if (this.value === item.label && !item.disabled) {
        this._selectedValue = { value: item.value, label: item.label, id: item.id };

        return;
      }
    }
  }

  private _syncSelectionItemsState(): void {
    if (!this._selectedValue) return;

    const items = this._getAllListItems();
    items.forEach(item => {
      item.selected = this._selectedValue.value === item.value && this._selectedValue.id === item.id;
    });
  }

  private _updateSlots = () => {
    this._leadingSlot = this.el.querySelector('[slot="leading-icon"]');
    this._trailingSlot = this.el.querySelector('[slot="trailing-icon"]');
  };

  private _handleComboboxClick = (): void => {
    if (this.disabled) return;

    this._expanded = !this._expanded;
  };

  private _updateSelectedValue(value: string, label: string, id: string): void {
    this._selectedValue = { value, label, id };

    this.wdprSelectionChange.emit({ selectedValue: this._selectedValue });
  }

  private get _hasSelection(): boolean {
    return this._selectedValue != null;
  }

  private get _displayValue(): string {
    if (!this._hasSelection) return this.value;

    return this._selectedValue.label;
  }

  private get _isListVisible(): boolean {
    return this._readyToShow && this._expanded && !this.isLoading && this._getAllListItems().length > 0 && !this.isErrorLoading;
  }

  render() {
    return (
      <Host onKeyDown={this._handleKeydown}>
        <div class={`chip-menu-wrapper ${this.alignment === 'left' ? 'chip-menu-align-start' : 'chip-menu-align-end'}`}>
          {this._renderChipDropdown()}
          {this._renderListWrapper()}
          {this._renderStatusMessage()}
        </div>
      </Host>
    );
  }
}
